parameters.inputSchema:
{
  "type": "object",
  "properties": {
    "title": {
      "type": "string",
      "description": "Short scroll-stopping title for the video, max 60 characters"
    },
    "script": {
      "type": "string",
      "description": "Spoken voiceover script, max 150 words, plain text only"
    },
    "keyword": {
      "type": "string",
      "description": "1-4 word English keyword for stock footage search"
    }
  }
}
